using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using Microsoft.Practices.EnterpriseLibrary.Data;
using System.Data.Common;
using System.Data;

namespace MaintenanceTasks
{
    class Program
    {
        
        static void Main(string[] args)
        {
            TouchwellTextTariffs();

            Database oDb = DatabaseFactory.CreateDatabase();
            DBMaintenance oDbM;
            CreateSPandCSharp oSP = new CreateSPandCSharp(oDb);
            oSP.OtherCreates();

            switch (args[0].ToLower())
            {
                case "fullbackup": oDbM = new DBMaintenance(oDb);
                    oDbM.CreateFullBackup(args[1], args[2]);
                    break;
                case "diffbackup": oDbM = new DBMaintenance(oDb);
                    oDbM.CreateFullBackup(args[1], args[2]);
                    break;
                case "triggers": oSP = new CreateSPandCSharp(oDb);
                    oSP.CreateTriggers();
                    break;
                default:
                    break;
            }
        }
